/* This Perl script accepts the latitude and longitude of two locations as input and calculates the distance between them using the Haversine formula */

use strict;
use warnings;
use Math::Trig qw(great_circle_distance deg2rad);

# Define input variables
my ($lat1, $lng1, $lat2, $lng2) = @ARGV;

# Define location names (optional)
my $location1 = "Location 1";
my $location2 = "Location 2";

# Verify input variables
die "Error: Invalid input\n" unless ($lat1 && $lng1 && $lat2 && $lng2);

# Convert degrees to radians
$lat1 = deg2rad($lat1);
$lng1 = deg2rad($lng1);
$lat2 = deg2rad($lat2);
$lng2 = deg2rad($lng2);

# Calculate distance using Haversine formula
my $distance_km = great_circle_distance($lng1, $lat1, $lng2, $lat2, 6371.009);

# Convert from kilometers to miles
my $distance_mi = $distance_km * 0.621371192;

# Print results
print "Distance between $location1 and $location2:\n";
printf("  %0.2f kilometers\n", $distance_km);
printf("  %0.2f miles\n", $distance_mi);

# Exit script
exit;

__END__

=head1 NAME

distance.pl - Calculate the distance between two locations using the Haversine formula

=head1 SYNOPSIS

perl distance.pl <latitude1> <longitude1> <latitude2> <longitude2>

=head1 DESCRIPTION

This Perl script accepts the latitude and longitude of two locations as input and calculates the distance between them using the Haversine formula. The output is in kilometers or miles, and includes the location names (optional) and the calculated distance.

