public class InsertionSort {

  public static void insertionSort(int[] arr) {

    for (int I = 1; I < arr.length; i++) {

      int currentElement = arr[i]; // save the current element
      int j = I - 1; // start comparing with the previous element

      while (j >= 0 && arr[j] > currentElement) {
        arr[j + 1] = arr[j]; // move the larger element to the right
        j--; // compare with the previous element
      }
      arr[j + 1] = currentElement; // insert the current element in its correct position
    }
  }

