// Bubble Sort in Swift
// This program sorts an array of integers in ascending order using the bubble sort algorithm.

// Function to perform bubble sort on an array of integers
func bubbleSort(_ array: [Int]) -> [Int] {
    var array = array
    let n = array.count

    // Traverse through all array elements
    for i in 0..<n {
        // Last i elements are already in place
        // So we need to traverse only up to n - i - 1
        for j in 0..<n - i - 1 {
            // Swap if the current element is greater than the next element
            if array[j] > array[j + 1] {
                let temp = array[j]
                array[j] = array[j + 1]
                array[j + 1] = temp
            }
        }
    }

    return array
}

